//-------------------------------------------------------------------------
// 무형자산제거버튼 활성화 체크
//-------------------------------------------------------------------------
scwin.f_checkRemoveBtn = function () {
    let vAcctDeptCd = scwin.vAcctDeptCd; // 소속 부서코드  
    let vEmpNo = scwin.vEmpNo; // 사용자아이디  

    if (vAcctDeptCd == "00009" || vEmpNo == "198015" || vEmpNo == "198078" || vEmpNo == "171577") { //권한 체크(재경팀일때만 가능), BIDC 이재설과장, 최현주 대리 추가 (박경진대리 퇴사로 최현주 대리 변경)
        if (ds_aset.getCellData(ds_aset.getRowPosition(), "bookAmt") == 0 && ds_master.getCellData(ds_master.getRowPosition(), "qty") != 0) { //장부가액이 0이고 수량이 0이 아닐때
            //무형자산제거 버튼 셋팅
            if (ds_master.getCellData(ds_master.getRowPosition(), "asetPatternCd") == "76" || ds_master.getCellData(ds_master.getRowPosition(), "asetPatternCd") == "78" ||
                ds_master.getCellData(ds_master.getRowPosition(), "asetPatternCd") == "80" || ds_master.getCellData(ds_master.getRowPosition(), "asetPatternCd") == "82" ||
                ds_master.getCellData(ds_master.getRowPosition(), "asetPatternCd") == "84" || ds_master.getCellData(ds_master.getRowPosition(), "asetPatternCd") == "88") {  //자산유형
                $c.gus.cfEnableObjects([btn_removeAset, ed_removeDt]);	//자산이력,감가상각이력조회 버튼 enable
            } else {
                $c.gus.cfDisableBtn([btn_removeAset, ed_removeDt]);
            }
        } else {
            $c.gus.cfDisableBtn([btn_removeAset, ed_removeDt]);
        }
    } else {
        $c.gus.cfDisableBtn([btn_removeAset, ed_removeDt]);
    }
}

//-------------------------------------------------------------------------
// 무형자산제거
//-------------------------------------------------------------------------
scwin.f_removeAset = async function () {
    if (ed_removeDt.getValue() == "") { //날짜 체크
        $c.win.alert("무형자산제거일자는 필수 입력입니다.");
        return;
    }

    let ret;
    ret = await $c.gus.cfValidate([ed_removeDt]);
    if (!ret) {
        return;
    }

    if (!$c.gus.cfIsNull(ed_removeDt.getValue())) {
        //ret = await $c.gus.cfValidateValue(ed_removeDt.getValue(),"minDate=" + ds_master.getCellData(ds_master.getRowPosition(),"acqDt"));

        var diff = $c.date.diffDate(ed_removeDt.getValue(), ds_master.getCellData(ds_master.getRowPosition(), "acqDt"));
        if (diff > 0) {
            $c.gus.cfAlertMsg("무형자산제거일자는 취득일자 이후이어야 합니다.");
            ed_removeDt.focus();
            return false;
        }
    }

    dma_removeAset.set("fixedAsetNo", ds_master.getCellData(ds_master.getRowPosition(), "fixedAsetNo"));  //자산번호
    dma_removeAset.set("removeDt", ed_removeDt.getValue());  //제거일자
    dma_removeAset.set("rmk", "무형자산제거 처리");  //비고

    ret = await $c.win.confirm("선택한 무형자산을 제거하시겠습니까?");
    if (ret) {
        //tr_removeAset.post();
        $c.sbm.execute(sbm_removeAset);
    }
}

